// Route: Token refresh
app.post('/auth/refresh', isAuthenticated, async (req, res) => {
  const tokens = req.session.tokens;

  if (!tokens || !tokens.refreshToken) {
    return res.status(400).json({ error: 'No refresh token available' });
  }

  try {
    const refreshResponse = await axios.post(
      OIDC_CONFIG.tokenEndpoint,
      new URLSearchParams({
        grant_type: 'refresh_token',
        refresh_token: tokens.refreshToken,
        client_id: OIDC_CONFIG.clientId,
        client_secret: OIDC_CONFIG.clientSecret,
      }).toString(),
      {
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
      }
    );

    const { access_token, refresh_token, id_token, expires_in } = refreshResponse.data;

    // Update session tokens
    req.session.tokens = {
      accessToken: access_token,
      refreshToken: refresh_token || tokens.refreshToken,
      tokenType: refreshResponse.data.token_type || tokens.tokenType,
      expiresAt: expires_in ? Date.now() + (expires_in * 1000) : null,
      idToken: id_token || tokens.idToken,
    };

    // If a new id_token was issued, update user claims
    if (id_token) {
      const decodedNewToken = jwt.decode(id_token);
      if (decodedNewToken) {
        req.session.user = {
          ...req.session.user,
          email: decodedNewToken.email || req.session.user.email,
          name: decodedNewToken.name || req.session.user.name,
        };
      }
    }

    console.log('Tokens refreshed successfully');
    res.json({ message: 'Tokens refreshed successfully' });
  } catch (refreshError) {
    console.error('Token refresh error:', refreshError.response?.data || refreshError.message);
    return res.status(500).json({
      error: 'Failed to refresh tokens',
      details: refreshError.response?.data || refreshError.message,
    });
  }
});

// Route: Logout
app.get('/auth/logout', (req, res) => {
  const idToken = req.session.tokens?.idToken;

  req.session.destroy((err) => {
    if (err) {
      console.error('Session destruction error:', err);
      return res.status(500).json({ error: 'Failed to logout' });
    }

    res.clearCookie('connect.sid');

    // Optionally redirect to OIDC provider's end session endpoint
    const endSessionUrl = `${OIDC_CONFIG.issuer}/logout`;
    const logoutUrl = new URL(endSessionUrl);
    if (idToken) {
      logoutUrl.searchParams.set('id_token_hint', idToken);
    }
    logoutUrl.searchParams.set('post_logout_redirect_uri', 'http://localhost:3000/');

    console.log('User logged out successfully');

    res.json({
      message: 'Logged out successfully',
      oidcLogoutUrl: logoutUrl.toString(),
    });
  });
});

// Route: Session status
app.get('/auth/status', (req, res) => {
  if (req.session && req.session.user) {
    const tokens = req.session.tokens;
    const isTokenExpired = tokens?.expiresAt ? Date.now() > tokens.expiresAt : false;

    res.json({
      authenticated: true,
      user: {
        sub: req.session.user.sub,
        email: req.session.user.email,
        name: req.session.user.name,
      },
      tokenStatus: {
        expired: isTokenExpired,
        expiresAt: tokens?.expiresAt ? new Date(tokens.expiresAt).toISOString() : null,
      },
    });
  } else {
    res.json({
      authenticated: false,
      loginUrl: '/auth/login',
    });
  }
});

